p.m:
\displaystyle{\begin{aligned}
  \frac{{\frac{4}{y-1}-4}}{{\frac{1}{y-1}+\frac{1}{y-10}}} \amp = \frac{({\frac{4}{y-1}-4})\cdot{\left(y-1\right)\mathopen{}\left(y-10\right)}}{({\frac{1}{y-1}+\frac{1}{y-10}})\cdot{\left(y-1\right)\mathopen{}\left(y-10\right)}} \\
    \amp = \frac{{\frac{4}{y-1}\mathopen{}\left(y-1\right)\mathopen{}\left(y-10\right)-4\mathopen{}\left(y-1\right)\mathopen{}\left(y-10\right)}}{{\frac{1}{y-1}\mathopen{}\left(y-1\right)\mathopen{}\left(y-10\right)+\frac{1}{y-10}\mathopen{}\left(y-1\right)\mathopen{}\left(y-10\right)}} \\
    \amp = \frac{{4\mathopen{}\left(y-10\right)-4\mathopen{}\left(y^{2}-11y+10\right)}}{{y-10+y-1}}, y \ne 1 \text{ and } y \ne 10 \\
    \amp = \frac{{4y-40-4y^{2}+44y-40}}{{2y-11}}, y \ne 1 \text{ and }  y \ne 10 \\
    \amp = \frac{{-4y^{2}+48y-40}}{{2y-11}}, y \ne 1 \text{ and }  y \ne 10 \\
    \amp = {-\frac{4\mathopen{}\left(y-2\right)\mathopen{}\left(y-10\right)}{2y-11}, y\ne 1\hbox{ and }y\ne 10}
\end{aligned}
    }
